-- Region V (Bicol): Camarines Norte, Camarines Sur, Albay, Sorsogon, Catanduanes, Masbate
-- BIR RDO 64-70 (latest DO-2024 revisions). Camarines Sur = RDO 65 (Naga) + 66 (Iriga) merged.
START TRANSACTION;
DELETE FROM zonal_values WHERE province IN ('CAMARINES NORTE','CAMARINES SUR','ALBAY','SORSOGON','CATANDUANES','MASBATE');
COMMIT;
